405: HostDescriptionImpl::HostDescriptionImpl(
406:     ClusterInfoConstSharedPtr cluster, const std::string& hostname,
407:     Network::Address::InstanceConstSharedPtr dest_address, MetadataConstSharedPtr metadata,
408:     const envoy::config::core::v3::Locality& locality,
409:     const envoy::config::endpoint::v3::Endpoint::HealthCheckConfig& health_check_config,
410:     uint32_t priority, TimeSource& time_source)
411:     : cluster_(cluster), hostname_(hostname),
412:       health_checks_hostname_(health_check_config.hostname()), address_(dest_address),
413:       canary_(Config::Metadata::metadataValue(metadata.get(),
414:                                               Config::MetadataFilters::get().ENVOY_LB,
415:                                               Config::MetadataEnvoyLbKeys::get().CANARY)
416:                   .bool_value()),
417:       metadata_(metadata), locality_(locality),
418:       locality_zone_stat_name_(locality.zone(), cluster->statsScope().symbolTable()),
419:       priority_(priority),
420:       socket_factory_(resolveTransportSocketFactory(dest_address, metadata_.get())),
421:       creation_time_(time_source.monotonicTime()) {
422:   if (health_check_config.port_value() != 0 && dest_address->type() != Network::Address::Type::Ip) {
423:     // Setting the health check port to non-0 only works for IP-type addresses. Setting the port
424:     // for a pipe address is a misconfiguration. Throw an exception.
425:     throwEnvoyExceptionOrPanic(
426:         fmt::format("Invalid host configuration: non-zero port for non-IP address"));
427:   }
428:   health_check_address_ = resolveHealthCheckAddress(health_check_config, dest_address);
