449: void HostImpl::setEdsHealthFlag(envoy::config::core::v3::HealthStatus health_status) {
450:   // Clear all old EDS health flags first.
451:   HostImpl::healthFlagClear(Host::HealthFlag::FAILED_EDS_HEALTH);
452:   HostImpl::healthFlagClear(Host::HealthFlag::DEGRADED_EDS_HEALTH);
453: 
454:   // Set the appropriate EDS health flag.
455:   switch (health_status) {
456:   case envoy::config::core::v3::UNHEALTHY:
457:     FALLTHRU;
458:   case envoy::config::core::v3::DRAINING:
459:     FALLTHRU;
460:   case envoy::config::core::v3::TIMEOUT:
461:     HostImpl::healthFlagSet(Host::HealthFlag::FAILED_EDS_HEALTH);
462:     break;
463:   case envoy::config::core::v3::DEGRADED:
464:     HostImpl::healthFlagSet(Host::HealthFlag::DEGRADED_EDS_HEALTH);
465:     break;
466:   default:
467:     break;
468:     // No health flags should be set.
469:   }
470: }
