484: Host::CreateConnectionData HostImpl::createConnection(
485:     Event::Dispatcher& dispatcher, const ClusterInfo& cluster,
486:     const Network::Address::InstanceConstSharedPtr& address,
487:     const std::vector<Network::Address::InstanceConstSharedPtr>& address_list,
488:     Network::UpstreamTransportSocketFactory& socket_factory,
489:     const Network::ConnectionSocket::OptionsSharedPtr& options,
490:     Network::TransportSocketOptionsConstSharedPtr transport_socket_options,
491:     HostDescriptionConstSharedPtr host) {
492:   auto source_address_selector = cluster.getUpstreamLocalAddressSelector();
493: 
494:   Network::ClientConnectionPtr connection;
495:   // If the transport socket options indicate the connection should be
496:   // redirected to a proxy, create the TCP connection to the proxy's address not
497:   // the host's address.
498:   if (transport_socket_options && transport_socket_options->http11ProxyInfo().has_value()) {
499:     auto upstream_local_address =
500:         source_address_selector->getUpstreamLocalAddress(address, options);
501:     ENVOY_LOG(debug, "Connecting to configured HTTP/1.1 proxy at {}",
502:               transport_socket_options->http11ProxyInfo()->proxy_address->asString());
503:     connection = dispatcher.createClientConnection(
504:         transport_socket_options->http11ProxyInfo()->proxy_address, upstream_local_address.address_,
505:         socket_factory.createTransportSocket(transport_socket_options, host),
506:         upstream_local_address.socket_options_, transport_socket_options);
507:   } else if (address_list.size() > 1) {
508:     connection = std::make_unique<Network::HappyEyeballsConnectionImpl>(
509:         dispatcher, address_list, source_address_selector, socket_factory, transport_socket_options,
510:         host, options);
511:   } else {
512:     auto upstream_local_address =
513:         source_address_selector->getUpstreamLocalAddress(address, options);
514:     connection = dispatcher.createClientConnection(
515:         address, upstream_local_address.address_,
516:         socket_factory.createTransportSocket(transport_socket_options, host),
517:         upstream_local_address.socket_options_, transport_socket_options);
518:   }
519: 
520:   connection->connectionInfoSetter().enableSettingInterfaceName(
521:       cluster.setLocalInterfaceNameOnUpstreamConnections());
522:   connection->setBufferLimits(cluster.perConnectionBufferLimitBytes());
523:   cluster.createNetworkFilterChain(*connection);
524:   return {std::move(connection), std::move(host)};
525: }
