566: void HostSetImpl::updateHosts(PrioritySet::UpdateHostsParams&& update_hosts_params,
567:                               LocalityWeightsConstSharedPtr locality_weights,
568:                               const HostVector& hosts_added, const HostVector& hosts_removed,
569:                               absl::optional<bool> weighted_priority_health,
570:                               absl::optional<uint32_t> overprovisioning_factor) {
571:   if (weighted_priority_health.has_value()) {
572:     weighted_priority_health_ = weighted_priority_health.value();
573:   }
574:   if (overprovisioning_factor.has_value()) {
575:     ASSERT(overprovisioning_factor.value() > 0);
576:     overprovisioning_factor_ = overprovisioning_factor.value();
577:   }
578:   hosts_ = std::move(update_hosts_params.hosts);
579:   healthy_hosts_ = std::move(update_hosts_params.healthy_hosts);
580:   degraded_hosts_ = std::move(update_hosts_params.degraded_hosts);
581:   excluded_hosts_ = std::move(update_hosts_params.excluded_hosts);
582:   hosts_per_locality_ = std::move(update_hosts_params.hosts_per_locality);
583:   healthy_hosts_per_locality_ = std::move(update_hosts_params.healthy_hosts_per_locality);
584:   degraded_hosts_per_locality_ = std::move(update_hosts_params.degraded_hosts_per_locality);
585:   excluded_hosts_per_locality_ = std::move(update_hosts_params.excluded_hosts_per_locality);
586:   locality_weights_ = std::move(locality_weights);
587: 
588:   // TODO(ggreenway): implement `weighted_priority_health` support in `rebuildLocalityScheduler`.
589:   rebuildLocalityScheduler(healthy_locality_scheduler_, healthy_locality_entries_,
590:                            *healthy_hosts_per_locality_, healthy_hosts_->get(), hosts_per_locality_,
591:                            excluded_hosts_per_locality_, locality_weights_,
592:                            overprovisioning_factor_);
593:   rebuildLocalityScheduler(degraded_locality_scheduler_, degraded_locality_entries_,
594:                            *degraded_hosts_per_locality_, degraded_hosts_->get(),
595:                            hosts_per_locality_, excluded_hosts_per_locality_, locality_weights_,
596:                            overprovisioning_factor_);
597: 
598:   runUpdateCallbacks(hosts_added, hosts_removed);
599: }
