601: void HostSetImpl::rebuildLocalityScheduler(
602:     std::unique_ptr<EdfScheduler<LocalityEntry>>& locality_scheduler,
603:     std::vector<std::shared_ptr<LocalityEntry>>& locality_entries,
604:     const HostsPerLocality& eligible_hosts_per_locality, const HostVector& eligible_hosts,
605:     HostsPerLocalityConstSharedPtr all_hosts_per_locality,
606:     HostsPerLocalityConstSharedPtr excluded_hosts_per_locality,
607:     LocalityWeightsConstSharedPtr locality_weights, uint32_t overprovisioning_factor) {
608:   // Rebuild the locality scheduler by computing the effective weight of each
609:   // locality in this priority. The scheduler is reset by default, and is rebuilt only if we have
610:   // locality weights (i.e. using EDS) and there is at least one eligible host in this priority.
611:   //
612:   // We omit building a scheduler when there are zero eligible hosts in the priority as
613:   // all the localities will have zero effective weight. At selection time, we'll either select
614:   // from a different scheduler or there will be no available hosts in the priority. At that point
615:   // we'll rely on other mechanisms such as panic mode to select a host, none of which rely on the
616:   // scheduler.
617:   //
618:   // TODO(htuch): if the underlying locality index ->
619:   // envoy::config::core::v3::Locality hasn't changed in hosts_/healthy_hosts_/degraded_hosts_, we
620:   // could just update locality_weight_ without rebuilding. Similar to how host
621:   // level WRR works, we would age out the existing entries via picks and lazily
622:   // apply the new weights.
623:   locality_scheduler = nullptr;
624:   if (all_hosts_per_locality != nullptr && locality_weights != nullptr &&
625:       !locality_weights->empty() && !eligible_hosts.empty()) {
626:     locality_scheduler = std::make_unique<EdfScheduler<LocalityEntry>>();
627:     locality_entries.clear();
628:     for (uint32_t i = 0; i < all_hosts_per_locality->get().size(); ++i) {
629:       const double effective_weight = effectiveLocalityWeight(
630:           i, eligible_hosts_per_locality, *excluded_hosts_per_locality, *all_hosts_per_locality,
631:           *locality_weights, overprovisioning_factor);
632:       if (effective_weight > 0) {
633:         locality_entries.emplace_back(std::make_shared<LocalityEntry>(i, effective_weight));
634:         locality_scheduler->add(effective_weight, locality_entries.back());
635:       }
636:     }
637:     // If all effective weights were zero, reset the scheduler.
638:     if (locality_scheduler->empty()) {
639:       locality_scheduler = nullptr;
640:     }
641:   }
642: }
