730: const HostSet&
731: PrioritySetImpl::getOrCreateHostSet(uint32_t priority,
732:                                     absl::optional<bool> weighted_priority_health,
733:                                     absl::optional<uint32_t> overprovisioning_factor) {
734:   if (host_sets_.size() < priority + 1) {
735:     for (size_t i = host_sets_.size(); i <= priority; ++i) {
736:       HostSetImplPtr host_set = createHostSet(i, weighted_priority_health, overprovisioning_factor);
737:       host_sets_priority_update_cbs_.push_back(
738:           host_set->addPriorityUpdateCb([this](uint32_t priority, const HostVector& hosts_added,
739:                                                const HostVector& hosts_removed) {
740:             runReferenceUpdateCallbacks(priority, hosts_added, hosts_removed);
741:           }));
742:       host_sets_.push_back(std::move(host_set));
743:     }
744:   }
745:   return *host_sets_[priority];
746: }
