1322:         lb_config.has_consistent_hashing_lb_config()) {
1323:       throwEnvoyExceptionOrPanic(
1324:           "cluster: load_balancing_policy cannot be combined with partial fields "
1325:           "(zone_aware_lb_config, "
1326:           "locality_weighted_lb_config, consistent_hashing_lb_config) of common_lb_config");
1327:     }
1328:   }
1329: 
1330:   absl::InlinedVector<absl::string_view, 4> missing_policies;
