1336:       // Load and validate the configuration.
1337:       auto proto_message = factory->createEmptyConfigProto();
1338:       Config::Utility::translateOpaqueConfig(policy.typed_extension_config().typed_config(),
1339:                                              context.messageValidationVisitor(), *proto_message);
1340: 
1341:       load_balancer_config_ =
1342:           factory->loadConfig(*proto_message, context.messageValidationVisitor());
1343: 
1344:       load_balancer_factory_ = factory;
