1400: ClusterInfoImpl::upstreamHttpProtocol(absl::optional<Http::Protocol> downstream_protocol) const {
1401:   if (downstream_protocol.has_value() &&
1402:       features_ & Upstream::ClusterInfo::Features::USE_DOWNSTREAM_PROTOCOL) {
1403:     if (downstream_protocol.value() == Http::Protocol::Http3 &&
1404:         !(features_ & Upstream::ClusterInfo::Features::HTTP3)) {
1405:       return {Http::Protocol::Http2};
1406:     }
1407:     // use HTTP11 since HTTP10 upstream is not supported yet.
1408:     if (downstream_protocol.value() == Http::Protocol::Http10) {
1409:       return {Http::Protocol::Http11};
1410:     }
1411:     return {downstream_protocol.value()};
1412:   }
1413: 
1414:   if (features_ & Upstream::ClusterInfo::Features::USE_ALPN) {
1415:     if (!(features_ & Upstream::ClusterInfo::Features::HTTP3)) {
1416:       return {Http::Protocol::Http2, Http::Protocol::Http11};
1417:     }
1418:     return {Http::Protocol::Http3, Http::Protocol::Http2, Http::Protocol::Http11};
1419:   }
1420: 
1421:   if (features_ & Upstream::ClusterInfo::Features::HTTP3) {
1422:     return {Http::Protocol::Http3};
1423:   }
1424: 
1425:   return {(features_ & Upstream::ClusterInfo::Features::HTTP2) ? Http::Protocol::Http2
1426:                                                                : Http::Protocol::Http11};
1427: }
