1723: void ClusterImplBase::reloadHealthyHosts(const HostSharedPtr& host) {
1724:   // Every time a host changes Health Check state we cause a full healthy host recalculation which
1725:   // for expensive LBs (ring, subset, etc.) can be quite time consuming. During startup, this
1726:   // can also block worker threads by doing this repeatedly. There is no reason to do this
1727:   // as we will not start taking traffic until we are initialized. By blocking Health Check
1728:   // updates while initializing we can avoid this.
1729:   if (initialization_complete_callback_ != nullptr) {
1730:     return;
1731:   }
1732: 
1733:   reloadHealthyHostsHelper(host);
1734: }
