529: std::vector<HostsPerLocalityConstSharedPtr> HostsPerLocalityImpl::filter(
530:     const std::vector<std::function<bool(const Host&)>>& predicates) const {
531:   // We keep two lists: one for being able to mutate the clone and one for returning to the
532:   // caller. Creating them both at the start avoids iterating over the mutable values at the end
533:   // to convert them to a const pointer.
534:   std::vector<std::shared_ptr<HostsPerLocalityImpl>> mutable_clones;
535:   std::vector<HostsPerLocalityConstSharedPtr> filtered_clones;
536: 
537:   mutable_clones.reserve(predicates.size());
538:   filtered_clones.reserve(predicates.size());
539:   for (size_t i = 0; i < predicates.size(); ++i) {
540:     mutable_clones.emplace_back(std::make_shared<HostsPerLocalityImpl>());
541:     filtered_clones.emplace_back(mutable_clones.back());
542:     mutable_clones.back()->local_ = local_;
543:   }
544: 
545:   for (const auto& hosts_locality : hosts_per_locality_) {
546:     std::vector<HostVector> current_locality_hosts;
547:     current_locality_hosts.resize(predicates.size());
548: 
549:     // Since # of hosts >> # of predicates, we iterate over the hosts in the outer loop.
550:     for (const auto& host : hosts_locality) {
551:       for (size_t i = 0; i < predicates.size(); ++i) {
552:         if (predicates[i](*host)) {
553:           current_locality_hosts[i].emplace_back(host);
554:         }
555:       }
556:     }
557: 
558:     for (size_t i = 0; i < predicates.size(); ++i) {
559:       mutable_clones[i]->hosts_per_locality_.push_back(std::move(current_locality_hosts[i]));
560:     }
561:   }
562: 
563:   return filtered_clones;
564: }
